model.jaffle_shop.customer_cohorts.raw_code:
with first_last as (
    select * from {{ ref('int_customer_first_last_orders') }}
),

cohorts as (
    select
        {{ dbt.date_trunc('month', 'first_order_date') }} as cohort_month,
        count(*) as cohort_size,
        avg(lifetime_orders) as avg_lifetime_orders,
        avg(customer_tenure_days) as avg_tenure_days
    from first_last
    group by {{ dbt.date_trunc('month', 'first_order_date') }}
)

select * from cohorts

model.jaffle_shop.int_daily_order_summar.raw_code:
{{
    config(
        materialized='incremental',
        unique_key='order_date'
    )
}}

with orders as (
    select * from {{ ref('int_order_enriched') }}
),

daily as (
    select
        order_date,
        count(*) as order_count,
        count(distinct customer_id) as unique_customers,
        sum(subtotal) as total_revenue,
        sum(total_cost) as total_cost,
        sum(total_margin) as total_margin,
        sum(total_quantity) as total_items_sold,
        sum(case when has_promotion then 1 else 0 end) as promoted_orders,
        sum(discount_amount) as total_discounts,
        avg(subtotal) as avg_order_value
    from orders

    {% if is_incremental() %}
    where order_date > (select max(order_date) from {{ this }})
    {% endif %}

    group by order_date
)

select * from daily
